function SegmentedBar({ value, accent }: { value: number; accent?: "sky" | "neutral" }) {
  const total = 12;
  const filled = Math.max(0, Math.min(total, value));
  const fillClass = accent === "sky" ? "bg-sky-300/90" : "bg-white/80";
  return (
    <div className="flex items-center gap-1">
      {Array.from({ length: total }).map((_, i) => (
        <span
          key={i}
          className={
            "dc_motion h-[18px] w-[6px] rounded-[2px] " +
            (i < filled ? fillClass : "bg-white/10")
          }
          style={i < filled ? { animation: `dc_bar_breathe ${2.6 + (i % 5) * 0.35}s ease-in-out infinite`, animationDelay: `${i * 120}ms` } : undefined}
        />
      ))}
    </div>
  );
}

